446:     /**
447:      * Returns true if a transactional request is sent or polled, or if a FindCoordinator request is enqueued
448:      */
449:     private boolean maybeSendAndPollTransactionalRequest() {
450:         if (transactionManager.hasInFlightRequest()) {
451:             // as long as there are outstanding transactional requests, we simply wait for them to return
452:             client.poll(retryBackoffMs, time.milliseconds());
453:             return true;
454:         }
455: 
456:         if (transactionManager.hasAbortableError()) {
457:             accumulator.abortUndrainedBatches(transactionManager.lastError());
458:         } else if (transactionManager.isAborting()) {
459:             accumulator.abortUndrainedBatches(new TransactionAbortedException());
460:         }
461: 
462:         TransactionManager.TxnRequestHandler nextRequestHandler = transactionManager.nextRequest(accumulator.hasIncomplete());
463:         if (nextRequestHandler == null)
464:             return false;
465: 
466:         AbstractRequest.Builder<?> requestBuilder = nextRequestHandler.requestBuilder();
467:         Node targetNode = null;
468:         try {
469:             FindCoordinatorRequest.CoordinatorType coordinatorType = nextRequestHandler.coordinatorType();
470:             targetNode = coordinatorType != null ?
471:                     transactionManager.coordinator(coordinatorType) :
472:                     client.leastLoadedNode(time.milliseconds()).node();
473:             if (targetNode != null) {
474:                 if (!awaitNodeReady(targetNode, coordinatorType)) {
475:                     log.trace("Target node {} not ready within request timeout, will retry when node is ready.", targetNode);
476:                     maybeFindCoordinatorAndRetry(nextRequestHandler);
477:                     return true;
478:                 }
479:             } else if (coordinatorType != null) {
480:                 log.trace("Coordinator not known for {}, will retry {} after finding coordinator.", coordinatorType, requestBuilder.apiKey());
481:                 maybeFindCoordinatorAndRetry(nextRequestHandler);
482:                 return true;
483:             } else {
484:                 log.trace("No nodes available to send requests, will poll and retry when until a node is ready.");
485:                 transactionManager.retry(nextRequestHandler);
486:                 client.poll(retryBackoffMs, time.milliseconds());
487:                 return true;
488:             }
489: 
490:             if (nextRequestHandler.isRetry())
491:                 time.sleep(nextRequestHandler.retryBackoffMs());
492: 
493:             long currentTimeMs = time.milliseconds();
494:             ClientRequest clientRequest = client.newClientRequest(targetNode.idString(), requestBuilder, currentTimeMs,
495:                 true, requestTimeoutMs, nextRequestHandler);
496:             log.debug("Sending transactional request {} to node {} with correlation ID {}", requestBuilder, targetNode, clientRequest.correlationId());
497:             client.send(clientRequest, currentTimeMs);
498:             transactionManager.setInFlightCorrelationId(clientRequest.correlationId());
499:             client.poll(retryBackoffMs, time.milliseconds());
500:             return true;
